import{_ as e,a}from"./chunks/export.Cp8QqQgk.js";import{_ as t,c as i,o as l,a4 as o}from"./chunks/framework.MPUiHh8R.js";const n="/minigame-unity-webgl-transform/assets/howtodebug1.D6NuTfM8.png",_=JSON.parse('{"title":"调试错误与异常处理","description":"","frontmatter":{},"headers":[],"relativePath":"Design/HowToDebug.md","filePath":"Design/HowToDebug.md"}'),r={name:"Design/HowToDebug.md"},s=o('<h1 id="调试错误与异常处理" tabindex="-1">调试错误与异常处理 <a class="header-anchor" href="#调试错误与异常处理" aria-label="Permalink to &quot;调试错误与异常处理&quot;">​</a></h1><p>本文描述Unity WebGL游戏运行过程中，如果遇到异常(业务代码、引擎)时开发者应该如何进行调试。</p><h2 id="开启代码异常" tabindex="-1">开启代码异常 <a class="header-anchor" href="#开启代码异常" aria-label="Permalink to &quot;开启代码异常&quot;">​</a></h2><img src="'+n+'" width="600"><blockquote><p>默认情况下，使用“转换插件”这两个选项都已设置完成。</p></blockquote><p>需要说明的是：</p><ul><li>Enable Exception如果设置为&quot;Full Without StackTrace&quot;时将会步骤更多引擎运行时产生的异常。</li><li>Enable Exception如果设置为&quot;Full With StackTrace&quot;时将会看到更多信息，但程序运行性能将受极大影响。</li><li>Debug Symbols不会对程序性能造成影响，该选项建议一直开启，用于后面做异常源码映射。</li></ul><h2 id="异常产生时如何排查" tabindex="-1">异常产生时如何排查 <a class="header-anchor" href="#异常产生时如何排查" aria-label="Permalink to &quot;异常产生时如何排查&quot;">​</a></h2><p>由于Unity WebGL运行时是基于WebAssembly，该格式并非“人类可读”，直接对WebAssembly进行调试会非常困难。 因此我们建议开发者使用日志与异常堆栈进行问题排查。对于未知问题，开发者往往需要异常产生时的堆栈找到蛛丝马迹，下文将引导开发者如何去根据WebAssembly找到对应的游戏工程源码所在位置。</p><h3 id="微信开发者工具" tabindex="-1">微信开发者工具 <a class="header-anchor" href="#微信开发者工具" aria-label="Permalink to &quot;微信开发者工具&quot;">​</a></h3><h3 id="真机环境" tabindex="-1">真机环境 <a class="header-anchor" href="#真机环境" aria-label="Permalink to &quot;真机环境&quot;">​</a></h3><ol><li>已验证Unity版本：2018.3/2018.4LTS、2019.2/2019.4LTS 安装时选择WebGL组件</li><li>如果你用的是Big Sur版本的Mac系统，并且Unity 版本小于 2019.4.14, 则需另外安装 <a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">python3</a>，并安装brotli 命令如下</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>python3 -m pip install brotli</span></span></code></pre></div><h2 id="二、unity导出webgl" tabindex="-1">二、Unity导出WebGL <a class="header-anchor" href="#二、unity导出webgl" aria-label="Permalink to &quot;二、Unity导出WebGL&quot;">​</a></h2><ol><li><p>下载 <a href="https://game.weixin.qq.com/cgi-bin/gamewxagwasmsplitwap/getunityplugininfo?download=1" target="_blank" rel="noreferrer">Unity插件</a>, 并导入至游戏项目中</p></li><li><p>添加需要导出的scene</p></li></ol><img src="'+e+'" width="600"><p>建议仅勾选Loading场景，后续场景使用AssetsBundle/Addressable进行按需加载。</p><h2 id="三、适配小游戏" tabindex="-1">三、适配小游戏 <a class="header-anchor" href="#三、适配小游戏" aria-label="Permalink to &quot;三、适配小游戏&quot;">​</a></h2><ol><li>Mac上授权<br> 因为Mac上的隐私安全问题，使用mac的用户需要先授权，使用window的用户跳过这步。点击&quot;微信小游戏&quot;-&gt;&quot;MacOS脚本授权&quot;,进行授权，直到不报错为止。若授权后还是报错，重启unity后再点授权试试。</li><li>选择 点击 微信小游戏 -&gt; 转换小游戏， 填写相应参数，点击<code>导出WEBGL并转换为小游戏</code>按钮 ，等待转换完成。</li></ol><img src="'+a+`" width="600"><p>其中：</p><ul><li>必须：appid 为 小游戏的Appid</li><li>必须：游戏资源CDN为首包资源所在的HTTP或CDN目录</li><li>可选：视频url 用来作为初始加载阶段的封面视频，视频格式请参考<a href="./video.html">视频规范</a></li><li>可选：AB包CDN地址为StreamingAssets目录的上一级注意末尾加<code>/</code>,若没有用到AB包则不需要填 生成目录下 webgl目录为游戏对应的webgl版本，minigame目录为转化后的小游戏代码。</li></ul><p>注意：</p><ul><li>将生成目录下的<code>webgl/ProjectName.data.unityweb.bin.txt</code>上传至“游戏资源CDN”。您的CDN最好支持Brotli或gzip压缩txt文件，这样能减少网络传输数据和时间。</li><li>项目使用了小游戏Unity适配插件，若小游戏是第一次使用本插件，在开发者工具会报错提示插件未授权，具体可参考<a href="./UsingLoader.html">使用Loader进行游游戏加载</a></li><li>使用AssetsBundle时，请将资源上传到“AB包CDN地址”</li></ul><p>至此，可以在<a href="https://developers.weixin.qq.com/miniprogram/dev/devtools/download.html" target="_blank" rel="noreferrer">微信开发者工具</a>打开转化后的小游戏进行预览。</p><h2 id="四、使用脚本集成到自己的构建系统" tabindex="-1">四、使用脚本集成到自己的构建系统 <a class="header-anchor" href="#四、使用脚本集成到自己的构建系统" aria-label="Permalink to &quot;四、使用脚本集成到自己的构建系统&quot;">​</a></h2><p>如果你希望将导出插件集成到自己的发布流程，想脚本调用的话，可修改 Assets/WX-WASM-SDK/Editor/MiniGameConfig.asset配置，然后调用WXEditorWindow 的 DoExport方法导出小游戏</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>var win = new WXEditorWindow();</span></span>
<span class="line"><span>win.DoExport();</span></span></code></pre></div><h2 id="五、常见问题" tabindex="-1">五、常见问题 <a class="header-anchor" href="#五、常见问题" aria-label="Permalink to &quot;五、常见问题&quot;">​</a></h2><ol><li>微信版本与运行时基础要求是什么？</li></ol><ul><li>Android版本必须&gt;=7.0.19</li><li>iOS版本必须&gt;=7.0.18</li><li>基础库版本必须&gt;=2.14.0 具体支持情况参考<a href="./SupportedPlatform.html">支持平台</a></li></ul><ol start="2"><li><p>为什么运行时出现奇怪的“Maximun call stack size exceeded.RangeError”或“Not Impletemented: Class::FromIL2CPPType”？ Unity WebGL 首包资源data文件含有metadata，如果data资源包和wasm对不上会有各种问题，尤其在<strong>浏览器</strong>运行时需清理IndexedDB中的缓存。</p></li><li><p>为什么资源或网络请求在打开&quot;vConsole&quot;正常，关闭时下载失败？ 网络请求必须<strong>配置安全域名</strong>：<a href="https://developers.weixin.qq.com/minigame/dev/guide/base-ability/network.html" target="_blank" rel="noreferrer">https://developers.weixin.qq.com/minigame/dev/guide/base-ability/network.html</a> 打开&quot;vConsole&quot;时，小游戏默认不检查因此能请求通过。</p></li><li><p>中文字体适配 字体必须打包到项目中，才能正常展示。</p></li><li><p>音频被切到后台会停止 小游戏被切到后台会停止播放音频需代码中监听 <a href="https://developers.weixin.qq.com/minigame/dev/api/base/app/life-cycle/wx.onShow.html" target="_blank" rel="noreferrer">WX.OnShow</a>事件和 <a href="https://developers.weixin.qq.com/minigame/dev/api/base/app/app-event/wx.onAudioInterruptionEnd.html" target="_blank" rel="noreferrer">WX.OnAudioInterruptionEnd</a>事件，在该事件之后重新播放音频</p></li></ol>`,32),p=[s];function d(h,c,u,m,b,g){return l(),i("div",null,p)}const f=t(r,[["render",d]]);export{_ as __pageData,f as default};
